        return self.cache.get(key)

    def set(self, key, value):
        self.cache[key] = value

    def delete(self, key):
        if key in self.cache:
            del self.cache[key]

    def save(self):
        # Save the cache to a file
        with open(self.index_file_path, 'wb') as f:
